async def scrape_sevenoaks(page, postcode, house_number):
    await page.goto('https://sevenoaks-dc-host01.oncreate.app/w/webpage/waste-collection-day')
    await page.fill('#address_search_postcode', postcode)
    await page.keyboard.press('Enter')
    await page.wait_for_selector('//select/option[2]')

    dropdown = page.locator('//select')
    options = await dropdown.locator('option').all_inner_texts()

    target_option = None
    if house_number:
        for option in options:
            if house_number.lower() in option.lower():
                target_option = option
                break

    if target_option:
        await dropdown.select_option(label=target_option)
    else:
        await dropdown.select_option(index=1)

    response_xpath = '//div[@data-class_name]//h4/../../../..'
    await page.wait_for_selector(response_xpath)
    elements = await page.locator(response_xpath).all()

    bins = []
    for element in elements:
        bin_type = await element.locator('h4').inner_text()
        date_text_elements = await element.locator('.//div[input]').all_inner_texts()
        if len(date_text_elements) > 1:
            raw_date = date_text_elements[1]
            if 'suspended' in raw_date.lower() or 'restarting' in raw_date.lower():
                continue
            bins.append({
                'type': bin_type.strip(),
                'collectionDate': raw_date.strip()
            })
    return bins

